import React, { useState, useMemo, useCallback } from "react";
import "./InternalPortal.css";
import {
  Box,
  Typography,
  Grid,
  Card,
  CardContent,
  Button,
  Drawer,
  TextField,
  LinearProgress,
  Snackbar,
  Alert,
  IconButton,
  InputAdornment,
  Tabs,
  Tab,
  Modal,
  Avatar,
  Switch,
  FormControlLabel,
  ThemeProvider,
  createTheme,
  Chip,
} from "@mui/material";
import { Close, Search, Brightness4, Brightness7 } from "@mui/icons-material";
import { DragDropContext, Droppable, Draggable } from "react-beautiful-dnd";

/* ================= CONSTANTS ================= */
const ROLES = { EMPLOYEE: "Employee", MANAGER: "Manager", HR: "HR" };
const STAGES = ["Applied", "Manager Review", "Technical Panel", "HR Decision"];

/* ================= MOCK USER ================= */
const currentUser = {
  id: "EMP101",
  name: "Sreekanth",
  role: ROLES.MANAGER, // Change this to test roles
  skills: ["React", "Redux", "SQL", "CSS", "MUI"],
  experience: 2,
};

/* ================= MOCK JOBS ================= */
const initialJobs = [
  {
    id: 1,
    title: "Frontend Engineer",
    company: "Abhishyandh Global Solutions",
    companyLogo: "https://via.placeholder.com/50",
    loc: "Hyderabad",
    type: "Full Time",
    salary: "₹8-12 LPA",
    minExperience: 1,
    postedDate: new Date("2026-02-01"),
    status: "Open",
    desc: `Build scalable UI systems using React, Redux, and MUI.`,
    coreSkills: ["React", "Redux", "MUI"],
    responsibilities: [
      "Develop responsive UIs",
      "Maintain component library",
      "Ensure cross-browser compatibility",
    ],
    requirements: ["React 2+ years", "Redux", "MUI", "CSS/HTML proficiency"],
    benefits: ["Health insurance", "Remote options", "Annual bonus"],
    applicants: [],
  },
  {
    id: 2,
    title: "Backend Node.js Developer",
    company: "Abhishyandh Global Solutions",
    companyLogo: "https://via.placeholder.com/50",
    loc: "Hyderabad",
    type: "Full Time",
    salary: "₹14-18 LPA",
    minExperience: 2,
    postedDate: new Date("2026-01-25"),
    status: "Open",
    desc: `Design and build scalable REST APIs and microservices.`,
    coreSkills: ["Node.js", "Express", "MongoDB"],
    responsibilities: [
      "Develop REST APIs",
      "Database optimization",
      "Ensure security",
    ],
    requirements: ["Node.js 2+ years", "MongoDB", "REST APIs", "Docker experience"],
    benefits: ["PF", "Medical coverage", "Flexible hours"],
    applicants: [],
  },
];

/* ================= HELPERS ================= */
const skillColor = (percent) =>
  percent >= 80 ? "#4caf50" : percent >= 50 ? "#ff9800" : "#f44336";

/* ================= COMPONENTS ================= */
const KpiCard = ({ label, value }) => (
  <Card sx={{ p: 2, textAlign: "center", boxShadow: 3 }}>
    <Typography variant="h6">{value}</Typography>
    <Typography variant="caption">{label}</Typography>
  </Card>
);

const JobCard = ({ job, skillMatch, onClick }) => (
  <Card
    onClick={onClick}
    sx={{
      cursor: "pointer",
      transition: "0.3s",
      "&:hover": { boxShadow: 6 },
    }}
  >
    <CardContent>
      <Box display="flex" alignItems="center" gap={2}>
        <Avatar src={job.companyLogo} />
        <Box>
          <Typography variant="h6">{job.title}</Typography>
          <Typography color="textSecondary">
            {job.company} • {job.loc}
          </Typography>
          <Typography variant="caption">
            Posted: {job.postedDate.toDateString()}
          </Typography>
        </Box>
      </Box>
      <Box mt={1}>
        <LinearProgress
          variant="determinate"
          value={skillMatch}
          sx={{
            height: 8,
            borderRadius: 5,
            "& .MuiLinearProgress-bar": { backgroundColor: skillColor(skillMatch) },
          }}
        />
        <Typography variant="caption">{skillMatch}% skill match</Typography>
      </Box>
      <Box mt={1}>
        {job.coreSkills.map((s) => (
          <Chip key={s} label={s} size="small" sx={{ mr: 0.5, mt: 0.5 }} />
        ))}
      </Box>
    </CardContent>
  </Card>
);

/* ================= MAIN COMPONENT ================= */
export default function InternalPortal() {
  const [jobs, setJobs] = useState(initialJobs);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [selectedJob, setSelectedJob] = useState(null);
  const [tab, setTab] = useState(0);
  const [resumeFile, setResumeFile] = useState(null);
  const [coverLetter, setCoverLetter] = useState("");
  const [snackbar, setSnackbar] = useState({ open: false, msg: "", sev: "success" });
  const [resumeModal, setResumeModal] = useState({ open: false, applicant: null });
  const [darkMode, setDarkMode] = useState(false);
  const [search, setSearch] = useState("");

  const [addJobModal, setAddJobModal] = useState(false);
  const [newJob, setNewJob] = useState({
    title: "",
    company: "Abhishyandh Global Solutions",
    companyLogo: "",
    loc: "",
    type: "Full Time",
    salary: "",
    minExperience: 0,
    desc: "",
    coreSkills: [],
    responsibilities: [],
    requirements: [],
    benefits: [],
    applicants: [],
  });

  const theme = useMemo(
    () =>
      createTheme({
        palette: { mode: darkMode ? "dark" : "light" },
      }),
    [darkMode]
  );

  const skillMatch = useCallback(
    (job) =>
      Math.round(
        (job.coreSkills.filter((s) => currentUser.skills.includes(s)).length /
          job.coreSkills.length) *
          100
      ),
    []
  );

  const isEligible = (job) =>
    skillMatch(job) >= 50 && currentUser.experience >= job.minExperience;

  const filteredJobs = useMemo(
    () =>
      jobs
        .filter(
          (j) =>
            j.title.toLowerCase().includes(search.toLowerCase()) ||
            j.company.toLowerCase().includes(search.toLowerCase())
        )
        .sort((a, b) => skillMatch(b) - skillMatch(a)),
    [jobs, search, skillMatch]
  );

  const totalApplicants = jobs.reduce((a, j) => a + (j.applicants?.length || 0), 0);
  const myApplications = jobs.filter((j) =>
    j.applicants?.some((a) => a.name === currentUser.name)
  ).length;

  /* ================= APPLY JOB ================= */
  const applyJob = () => {
    if (!resumeFile)
      return setSnackbar({ open: true, msg: "Upload your resume first", sev: "error" });
    if (!isEligible(selectedJob))
      return setSnackbar({ open: true, msg: "Not eligible", sev: "warning" });
    if (selectedJob.applicants?.some((a) => a.name === currentUser.name))
      return setSnackbar({ open: true, msg: "Already applied", sev: "info" });

    const applicant = {
      name: currentUser.name,
      status: "Applied",
      skills: currentUser.skills,
      resume: resumeFile.name,
      cover: coverLetter,
      appliedDate: new Date(),
    };

    setJobs((prev) =>
      prev.map((j) =>
        j.id === selectedJob.id
          ? { ...j, applicants: [...(j.applicants || []), applicant] }
          : j
      )
    );

    setSnackbar({ open: true, msg: "Applied Successfully!", sev: "success" });
    setResumeFile(null);
    setCoverLetter("");
    setDrawerOpen(false);
  };

  const updateApplicantStage = (applicantName, updates) => {
    setJobs((prev) =>
      prev.map((j) =>
        j.id === selectedJob?.id
          ? {
              ...j,
              applicants: (j.applicants || []).map((a) =>
                a.name === applicantName ? { ...a, ...updates } : a
              ),
            }
          : j
      )
    );
  };

  const onDragEnd = (result) => {
    if (!result.destination) return;
    const applicantName = result.draggableId;
    const newStage = result.destination.droppableId;
    updateApplicantStage(applicantName, { status: newStage, stageDate: new Date() });
  };

  const handleAddJob = () => {
    if (!newJob.title || !newJob.loc || !newJob.desc)
      return setSnackbar({ open: true, msg: "Fill required fields", sev: "error" });

    const jobToAdd = { ...newJob, id: jobs.length + 1, postedDate: new Date(), status: "Open" };
    setJobs((prev) => [...prev, jobToAdd]);
    setAddJobModal(false);
    setNewJob({
      title: "",
      company: "Abhishyandh Global Solutions",
      companyLogo: "",
      loc: "",
      type: "Full Time",
      salary: "",
      minExperience: 0,
      desc: "",
      coreSkills: [],
      responsibilities: [],
      requirements: [],
      benefits: [],
      applicants: [],
    });
    setSnackbar({ open: true, msg: "Job added successfully!", sev: "success" });
  };

  return (
    <ThemeProvider theme={theme}>
      <Box p={3} sx={{ maxWidth: "1200px", margin: "auto" }}>
        {/* HEADER */}
        <Box
  display="flex"
  justifyContent="space-between"
  alignItems="center"
  mb={4}
>
          <Typography variant="h4">Internal Job Portal</Typography>
          <Box display="flex" gap={2} alignItems="center">
            <FormControlLabel
              control={<Switch checked={darkMode} onChange={() => setDarkMode(!darkMode)} />}
              label={darkMode ? <Brightness7 /> : <Brightness4 />}
            />
            {(currentUser.role === ROLES.HR || currentUser.role === ROLES.MANAGER) && (
              <Button variant="contained" onClick={() => setAddJobModal(true)}>Add Job</Button>
            )}
          </Box>
        </Box>

        {/* KPI CARDS */}
        <Grid container spacing={2} mb={3}>
          <Grid item xs={12} md={4}><KpiCard label="Open Positions" value={jobs.length} /></Grid>
          <Grid item xs={12} md={4}><KpiCard label="Total Applicants" value={totalApplicants} /></Grid>
          <Grid item xs={12} md={4}><KpiCard label="Your Applications" value={myApplications} /></Grid>
        </Grid>

        {/* SEARCH */}
        <Box display="flex" gap={2} mb={2}>
          <TextField
            fullWidth
            placeholder="Search jobs"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            InputProps={{ startAdornment: <InputAdornment position="start"><Search /></InputAdornment> }}
          />
        </Box>

        {/* JOB CARDS */}
        <Grid container spacing={4}>
          {filteredJobs.map((job) => (
            <Grid item xs={12} md={6} key={job.id}>
              <JobCard
                job={job}
                skillMatch={skillMatch(job)}
                onClick={() => { setSelectedJob(job); setDrawerOpen(true); setTab(0); }}
              />
            </Grid>
          ))}
        </Grid>

        {/* ================= JOB DRAWER ================= */}
        <Drawer
          anchor="right"
          open={drawerOpen}
          onClose={() => setDrawerOpen(false)}
          PaperProps={{ sx: { width: 600, p: 3 } }}
        >
          {selectedJob && (
            <>
              <Box display="flex" justifyContent="space-between" mb={2}>
                <Typography variant="h5">{selectedJob.title}</Typography>
                <IconButton onClick={() => setDrawerOpen(false)}><Close /></IconButton>
              </Box>

              <Tabs value={tab} onChange={(e, v) => setTab(v)} sx={{ mb: 2 }}>
                <Tab label="Description" />
                <Tab label="Apply" />
                {(currentUser.role === ROLES.MANAGER || currentUser.role === ROLES.HR) && <Tab label="Applicants" />}
              </Tabs>

              {/* DESCRIPTION TAB */}
              {tab === 0 && (
                <Box>
                  <Typography variant="subtitle1">{selectedJob.desc}</Typography>
                  <Typography fontWeight="bold" mt={1}>Responsibilities:</Typography>
                  {selectedJob.responsibilities.map((r, i) => <Typography key={i}>• {r}</Typography>)}
                  <Typography fontWeight="bold" mt={1}>Requirements:</Typography>
                  {selectedJob.requirements.map((r, i) => <Typography key={i}>• {r}</Typography>)}
                  <Typography fontWeight="bold" mt={1}>Benefits:</Typography>
                  {selectedJob.benefits.map((b, i) => <Typography key={i}>• {b}</Typography>)}
                </Box>
              )}

              {/* APPLY TAB */}
              {tab === 1 && (
                <Box display="flex" flexDirection="column" gap={2}>
                  <TextField type="file" onChange={(e) => setResumeFile(e.target.files[0])} />
                  <TextField label="Cover Letter" multiline rows={4} value={coverLetter} onChange={(e) => setCoverLetter(e.target.value)} />
                  <Button variant="contained" disabled={!isEligible(selectedJob)} onClick={applyJob}>Apply</Button>
                </Box>
              )}

              {/* APPLICANTS TAB */}
              {tab === 2 && (currentUser.role === ROLES.MANAGER || currentUser.role === ROLES.HR) && (
                <DragDropContext onDragEnd={onDragEnd}>
                  <Box display="flex" gap={2} mt={2} overflow="auto">
                    {STAGES.map((stage) => (
                      <Droppable droppableId={stage} key={stage}>
                        {(provided) => (
                          <Box
                            ref={provided.innerRef}
                            {...provided.droppableProps}
                            sx={{ width: 200, bgcolor: "#f4f6f9", p: 1, borderRadius: 2, minHeight: 150 }}
                          >
                            <Typography fontWeight="bold">{stage}</Typography>

                            {selectedJob.applicants.filter(a => a.status === stage).map((a, i) => (
                              <Draggable draggableId={a.name} index={i} key={a.name}>
                                {(prov) => (
                                  <Card
                                    ref={prov.innerRef}
                                    {...prov.draggableProps}
                                    {...prov.dragHandleProps}
                                    sx={{ p: 1, mt: 1 }}
                                  >
                                    <Typography fontWeight="bold">{a.name}</Typography>

                                    {/* Manager Comments */}
                                    {stage === "Manager Review" && currentUser.role === ROLES.MANAGER && (
                                      <TextField
                                        size="small"
                                        label="Comments"
                                        fullWidth
                                        value={a.managerComments || ""}
                                        onChange={(e) => updateApplicantStage(a.name, { managerComments: e.target.value })}
                                      />
                                    )}

                                    {/* HR Decision */}
                                    {stage === "HR Decision" && currentUser.role === ROLES.HR && (
                                      <Box display="flex" gap={1} mt={1}>
                                        <Button size="small" variant="contained" color="success" onClick={() => updateApplicantStage(a.name, { status: "Approved" })}>Approve</Button>
                                        <Button size="small" variant="contained" color="error" onClick={() => updateApplicantStage(a.name, { status: "Rejected" })}>Reject</Button>
                                      </Box>
                                    )}

                                    <Button size="small" sx={{ mt: 1 }} onClick={() => setResumeModal({ open: true, applicant: a })}>Resume</Button>
                                  </Card>
                                )}
                              </Draggable>
                            ))}

                            {provided.placeholder}
                          </Box>
                        )}
                      </Droppable>
                    ))}
                  </Box>
                </DragDropContext>
              )}
            </>
          )}
        </Drawer>

        {/* ADD JOB MODAL */}
        <Modal open={addJobModal} onClose={() => setAddJobModal(false)}>
          <Box sx={{ bgcolor: "#fff", p: 4, width: 500, mx: "auto", mt: "5%", borderRadius: 2, maxHeight: "90%", overflowY: "auto" }}>
            <Typography variant="h6" mb={2}>Add New Job</Typography>
            <TextField label="Job Title" fullWidth value={newJob.title} onChange={(e) => setNewJob({ ...newJob, title: e.target.value })} sx={{ mb: 2 }} />
            <TextField label="Location" fullWidth value={newJob.loc} onChange={(e) => setNewJob({ ...newJob, loc: e.target.value })} sx={{ mb: 2 }} />
            <TextField label="Description" multiline rows={4} fullWidth value={newJob.desc} onChange={(e) => setNewJob({ ...newJob, desc: e.target.value })} sx={{ mb: 2 }} />
            <TextField label="Minimum Experience" type="number" fullWidth value={newJob.minExperience} onChange={(e) => setNewJob({ ...newJob, minExperience: parseInt(e.target.value) })} sx={{ mb: 2 }} />
            <Button variant="contained" onClick={handleAddJob}>Add Job</Button>
          </Box>
        </Modal>

        {/* RESUME MODAL */}
        <Modal open={resumeModal.open} onClose={() => setResumeModal({ open: false, applicant: null })}>
          <Box sx={{ bgcolor: "#fff", p: 4, width: 500, mx: "auto", mt: "5%", borderRadius: 2 }}>
            {resumeModal.applicant && (
              <>
                <Typography variant="h6">{resumeModal.applicant.name}'s Resume</Typography>
                <Typography mt={1}>Resume File: {resumeModal.applicant.resume}</Typography>
                <Typography mt={1}>Cover Letter: {resumeModal.applicant.cover}</Typography>
              </>
            )}
          </Box>
        </Modal>

        {/* SNACKBAR */}
        <Snackbar
          open={snackbar.open}
          autoHideDuration={4000}
          onClose={() => setSnackbar({ ...snackbar, open: false })}
        >
          <Alert severity={snackbar.sev}>{snackbar.msg}</Alert>
        </Snackbar>
      </Box>
    </ThemeProvider>
  );
}
